1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[true]])).toEqual([]);
10	  });
11	  it("should return empty grid for two live cells (underpopulation)", () => {
12	    expect(nextGeneration([[true, true]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has exactly 2 live neighbors", () => {
15	    const grid = [[true, true, true]];
16	    const result = nextGeneration(grid);
17	    expect(result[0][1]).toBe(true);
18	  });
19	  it("should keep a live cell alive when it has exactly 3 live neighbors", () => {
20	    const grid = [[true, true], [true, true]];
21	    const result = nextGeneration(grid);
22	    expect(result[0][0]).toBe(true);
23	  });
24	  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
25	  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
26	  it.todo("should keep a block (2x2) unchanged as a still life");
27	  it.todo("should transform a blinker from vertical to horizontal");
28	});
29

1	export function nextGeneration(grid: boolean[][]): boolean[][] {
2	  if (grid.length === 0) return [];
3	  const rows = grid.length;
4	  const cols = grid[0].length;
5	  const countNeighbors = (r: number, c: number): number => {
6	    let count = 0;
7	    for (let dr = -1; dr <= 1; dr++) {
8	      for (let dc = -1; dc <= 1; dc++) {
9	        if (dr === 0 && dc === 0) continue;
10	        const nr = r + dr;
11	        const nc = c + dc;
12	        if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && grid[nr][nc]) count++;
13	      }
14	    }
15	    return count;
16	  };
17	  const result: boolean[][] = [];
18	  for (let r = 0; r < rows; r++) {
19	    const row: boolean[] = [];
20	    for (let c = 0; c < cols; c++) {
21	      const neighbors = countNeighbors(r, c);
22	      const alive = grid[r][c];
23	      const survives = alive && (neighbors === 2 || neighbors === 3);
24	      const isReborn = !alive && neighbors === 3;
25	      row.push(survives || isReborn);
26	    }
27	    result.push(row);
28	  }
29	  const hasLiveCell = result.some(row => row.some(cell => cell));
30	  return hasLiveCell ? result : [];
31	}
